-- Catalogo condiviso Wandex: province italiane, capitali europee, capitali del mondo.
-- Non ha utente_id: è lo stesso elenco per tutti gli utenti; chi ha visitato cosa
-- resta in wandex_voci (quella sì per-utente).
CREATE TABLE IF NOT EXISTS wandex_catalogo (
  id        INTEGER PRIMARY KEY AUTOINCREMENT,
  categoria TEXT NOT NULL,
  chiave    TEXT NOT NULL,
  nome      TEXT NOT NULL,
  gruppo    TEXT,
  paese     TEXT,
  iso       TEXT,
  lat       REAL,
  lng       REAL,
  UNIQUE(categoria, chiave)
);

